#include <vector>
#include <stack>
#include <algorithm>
#include <unordered_map>

std::vector<int> findEulerianPath(int n, std::unordered_map<int, std::vector<int>>& adj) {
    std::stack<int> st;
    std::vector<int> path;
    st.push(0); // Start node (assumed 0 here)

    while (!st.empty()) {
        int u = st.top();
        if (!adj[u].empty()) {
            int v = adj[u].back();
            adj[u].pop_back();
            st.push(v);
        } else {
            path.push_back(u);
            st.pop();
        }
    }
    std::reverse(path.begin(), path.end());
    return path;
}

