    const stack = [startNode];
    const path = [];

    while (stack.length > 0) {
        const u = stack[stack.length - 1];
        if (adj[u] && adj[u].length > 0) {
            const v = adj[u].pop();
            stack.push(v);
        } else {
            path.push(stack.pop());
        }
    }
    return path.reverse();
